// ============================================================================
// Lookup indexes (lazy-built for performance)
// ============================================================================

let _slugIndex: Map<string, LegalSituation> | null = null
let _paIndex: Map<string, LegalSituation[]> | null = null

function buildSlugIndex(): Map<string, LegalSituation> {
  if (!_slugIndex) {
    _slugIndex = new Map()
    for (const s of SITUATIONS) {
      _slugIndex.set(s.slug, s)
    }
  }
  return _slugIndex
}

function buildPAIndex(): Map<string, LegalSituation[]> {
  if (!_paIndex) {
    _paIndex = new Map()
    for (const s of SITUATIONS) {
      const arr = _paIndex.get(s.practiceAreaSlug) ?? []
      arr.push(s)
      _paIndex.set(s.practiceAreaSlug, arr)
    }
  }
  return _paIndex
}

/**
 * Look up a legal situation by its URL-safe slug.
 */
export function getSituationBySlug(slug: string): LegalSituation | undefined {
  return buildSlugIndex().get(slug)
}

/**
 * Get all situations that map to a given practice area slug.
 */
export function getSituationsByPracticeArea(paSlug: string): LegalSituation[] {
  return buildPAIndex().get(paSlug) ?? []
}

/**
 * Get all situations with high urgency, sorted alphabetically.
 */
export function getHighUrgencySituations(): LegalSituation[] {
  return SITUATIONS
    .filter(s => s.urgency === 'high')
    .sort((a, b) => a.name.localeCompare(b.name))
}
